-- =============================================================================
-- Cervical Cancer DSS - PostgreSQL Schema

-- Published Date: April 24, 2026 
-- Publishing Members: Esha Pandya, Abigail Torbatian, Devavrath Sandeep 
-- =============================================================================

DROP SCHEMA public CASCADE; 
CREATE SCHEMA public;

-- ENUM TYPES 
-- =============================================================================
CREATE TYPE APP_USER_ROLE AS ENUM ('physician', 'nurse', 'manager');
CREATE TYPE RECOMMENDATION_CATEGORY AS ENUM ('routine recall', 'expedited testing', 'referral');
CREATE TYPE FOLLOWUP_STATUS AS ENUM('pending', 'scheduled', 'complete', 'cancelled', 'no show'); 
CREATE TYPE ORDER_STATUS AS ENUM('ordered', 'in progress', 'resulted', 'cancelled'); 
CREATE TYPE LAB_INTERPRETATION AS ENUM ('normal', 'abnormal', 'malignant', 'benign', 'unclear', 'unsatisfactory');
CREATE TYPE RISK_LEVEL AS ENUM ('low', 'medium', 'high'); 
CREATE TYPE DIAGNOSIS_TYPE AS ENUM('current', 'historical'); 
CREATE TYPE LOINC_CATEGORY AS ENUM('order', 'result', 'risk_factor'); 
CREATE TYPE SNOMED_TYPE AS ENUM('finding', 'disorder', 'observable entity'); 

-- DATA DEFINITION 
-- =============================================================================

-- REFERENCE TABLES 
-- =============================================================================
CREATE TABLE LOINC_Reference (
  loinc_code VARCHAR(15) PRIMARY KEY, 
  long_name VARCHAR(255) NOT NULL, 
  short_name VARCHAR(100), 
  component VARCHAR(100), 
  specimen VARCHAR(50), 
  scale VARCHAR(20), 
  category LOINC_CATEGORY 
); 

CREATE TABLE ICD10_Reference (
  icd10_code VARCHAR(10) PRIMARY KEY, 
  description VARCHAR(255) NOT NULL, 
  category VARCHAR(100) -- clinical grouping for dashboard filtering 
); 

CREATE TABLE SNOMED_Reference ( 
  snomed_code VARCHAR(20) PRIMARY KEY, 
  description VARCHAR(255) NOT NULL, 
  concept_type SNOMED_TYPE 
); 

-- CORE APPLICATION TABLES 
-- =============================================================================
CREATE TABLE App_User (
  user_id UUID PRIMARY KEY,
  first_name VARCHAR(30) NOT NULL,
  last_name VARCHAR(30) NOT NULL,
  email VARCHAR(100) NOT NULL UNIQUE, 
  password_hash VARCHAR(255) NOT NULL, 
  role APP_USER_ROLE NOT NULL, 
  npi_number VARCHAR(10) UNIQUE, -- clinicians only, nullable 
  is_active BOOLEAN NOT NULL DEFAULT TRUE, 
  last_login TIMESTAMP, 
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, 
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP 
);

CREATE TABLE Patient (
  patient_id UUID PRIMARY KEY,
  first_name VARCHAR(50) NOT NULL, 
  last_name VARCHAR(50) NOT NULL, 
  dob DATE NOT NULL,
  race VARCHAR(100), 
  ethnicity VARCHAR(50), 
  sex VARCHAR(10), -- biological 
  gender_identity VARCHAR(50), 
  email VARCHAR(100), 
  phone_contact VARCHAR(20), 
  address VARCHAR(255), 
  preferred_language VARCHAR(75) DEFAULT 'English', 
  hysterectomy BOOLEAN NOT NULL DEFAULT False, 
  is_active BOOLEAN DEFAULT TRUE, 
  primary_provider UUID REFERENCES app_user(user_id), -- care continuity 
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, 
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP 
);

CREATE TABLE Encounter (
  encounter_id UUID PRIMARY KEY,
  patient_id UUID NOT NULL REFERENCES patient(patient_id),
  clinician_id UUID NOT NULL REFERENCES app_user(user_id),
  encounter_date DATE DEFAULT CURRENT_DATE 
);

CREATE TABLE Diagnosis (
  diagnosis_id UUID PRIMARY KEY, 
  encounter_id UUID NOT NULL REFERENCES encounter(encounter_id), 
  entered_by UUID NOT NULL REFERENCES app_user(user_id), 
  icd10_code VARCHAR(10) NOT NULL REFERENCES ICD10_reference(icd10_code), 
  diagnosis_type DIAGNOSIS_TYPE NOT NULL DEFAULT 'current', 
  notes VARCHAR(255), 
  recorded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP 
); 

-- Used by the explainability layer and population dashboard for display
CREATE TABLE Risk_Factor_Catalog ( 
  factor_code VARCHAR(50) PRIMARY KEY, 
  display_name VARCHAR(100) NOT NULL, 
  loinc_code VARCHAR(15) REFERENCES LOINC_reference(loinc_code), 
  snomed_code VARCHAR(20) REFERENCES SNOMED_reference(snomed_code), 
  data_type VARCHAR(20), 
  units VARCHAR(30), 
  description TEXT 
); 

CREATE TABLE Risk_Assessment (
  assessment_id UUID PRIMARY KEY,
  encounter_id UUID NOT NULL REFERENCES encounter(encounter_id),
  entered_by UUID NOT NULL REFERENCES app_user(user_id), 
  age_at_assessment INTEGER NOT NULl,
  num_sexual_partners INTEGER, 
  num_pregnancies INTEGER, 
  smokes BOOLEAN, 
  smokes_years FLOAT, 
  smokes_packs_year FLOAT, 
  hormonal_contraceptives BOOLEAN, 
  hc_years FLOAT, 
  iud BOOLEAN, 
  iud_years FLOAT, 
  std BOOLEAN, 
  std_count INTEGER, 
  -- derived from Diagnosis table 
  dx_cancer BOOLEAN DEFAULT FALSE, -- ICD-10: C53.x 
  dx_cin BOOLEAN DEFAULT FALSE, -- ICD-10: N87.x 
  dx_hpv BOOLEAN DEFAULT FALSE, -- ICD-10: B97.7 
  entered_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP 
);

CREATE TABLE DSS_Recommendation (
  recommendation_id UUID PRIMARY KEY,
  assessment_id UUID NOT NULL REFERENCES risk_assessment(assessment_id),
  predicted_probability FLOAT NOT NULL CHECK (predicted_probability BETWEEN 0 AND 1),
  risk_level RISK_LEVEL NOT NULL, 
  recommendation_category RECOMMENDATION_CATEGORY NOT NULL, 
  model_version VARCHAR(20), 
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP 
);

CREATE TABLE Risk_Driver (
  driver_id UUID PRIMARY KEY,
  recommendation_id UUID NOT NULL REFERENCES DSS_recommendation(recommendation_id),
  factor_code VARCHAR(50) REFERENCES risk_factor_catalog(factor_code), 
  feature_value FLOAT NOT NULL, 
  importance_score FLOAT NOT NULL, 
  rank INT NOT NULL 
);

CREATE TABLE Override (
  override_id UUID PRIMARY KEY,
  recommendation_id UUID NOT NULL REFERENCES DSS_recommendation(recommendation_id),
  override_user_id UUID NOT NULL REFERENCES app_user(user_id),
  original_category RECOMMENDATION_CATEGORY NOT NULL, 
  new_category RECOMMENDATION_CATEGORY NOT NULL, 
  reasoning VARCHAR(500) NOT NULL, 
  entered_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP 
);

CREATE TABLE Follow_Up (
  follow_up_id UUID PRIMARY KEY,
  encounter_id UUID NOT NULL REFERENCES encounter(encounter_id),
  patient_id UUID NOT NULL REFERENCES patient(patient_id),
  assigned_to UUID REFERENCES app_user(user_id), 
  recommended_action RECOMMENDATION_CATEGORY NOT NULL, 
  status FOLLOWUP_STATUS NOT NULL DEFAULT 'pending', 
  due_date DATE, 
  updated_by UUID REFERENCES app_user(user_id), 
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP 
);

CREATE TABLE Appointment (
  appointment_id UUID PRIMARY KEY,
  follow_up_id UUID NOT NULL REFERENCES follow_up(follow_up_id),
  patient_id UUID NOT NULL REFERENCES patient(patient_id),
  clinician_id UUID REFERENCES app_user(user_id), 
  appointment_type VARCHAR(50) NOT NULL, 
  scheduled_date TIMESTAMP NOT NULL, 
  status FOLLOWUP_STATUS NOT NULL 
);

-- SCREENING & LAB TABLES
-- Standards: LOINC for order and result codes, SNOMED CT for result findings
-- =============================================================================
CREATE TABLE Screening_Order (
  order_id UUID PRIMARY KEY, 
  encounter_id UUID NOT NULL REFERENCES encounter(encounter_id), 
  ordered_by UUID NOT NULL REFERENCES app_user(user_id), 
  loinc_code VARCHAR(15) NOT NULL REFERENCES LOINC_reference(loinc_code),  
  order_type VARCHAR(50) NOT NULL, 
  status ORDER_STATUS NOT NULL DEFAULT 'ordered', 
  ordered_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP 
); 

CREATE TABLE Lab_Result (
  result_id UUID PRIMARY KEY, 
  order_id UUID NOT NULL REFERENCES screening_order(order_id), 
  loinc_code VARCHAR(15) NOT NULL REFERENCES LOINC_reference(loinc_code), 
  snomed_result_code VARCHAR(20) REFERENCES SNOMED_reference(snomed_code), 
  result_unit VARCHAR(25), 
  result_value VARCHAR(100) NOT NULL, 
  interpretation LAB_INTERPRETATION NOT NULL, 
  result_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP 
); 

